"""Reusable responsive shared-player renderer for geometric ray diagrams."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.rayConfig||{},rays=c.rays||[],xmin=c.xmin??-5,xmax=c.xmax??5,ymin=c.ymin??-4,ymax=c.ymax??4,X=x=>35+(x-xmin)/(xmax-xmin)*(w-70),Y=y=>h-30-(y-ymin)/(ymax-ymin)*(h-60);PhysicsExperience.context(ctx,s,'opticsBench');ctx.strokeStyle=PhysicsVisuals.token(s,'colors','text_muted','#526577');ctx.beginPath();ctx.moveTo(X(xmin),Y(0));ctx.lineTo(X(xmax),Y(0));ctx.stroke();if(c.interface){ctx.strokeStyle=PhysicsVisuals.token(s,'colors','text','#152536');ctx.beginPath();ctx.moveTo(X(0),Y(ymin));ctx.lineTo(X(0),Y(ymax));ctx.stroke()}if(c.lens){ctx.strokeStyle=PhysicsVisuals.token(s,'colors','electric_field','#006D77');ctx.lineWidth=5;ctx.beginPath();ctx.moveTo(X(0),Y(ymin*.75));ctx.quadraticCurveTo(X(c.lensSign*.22),Y(0),X(0),Y(ymax*.75));ctx.stroke()}const visible=Math.ceil(s.fraction*rays.length);for(let i=0;i<visible;i++){const r=rays[i];ctx.setLineDash(r.kind==='virtual'?[7,6]:[]);ctx.strokeStyle=r.kind==='virtual'?PhysicsVisuals.token(s,'colors','magnetic_field','#7E22CE'):PhysicsVisuals.token(s,'colors',i===0?'net_force':'energy','#B45309');ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(X(r.x1),Y(r.y1));ctx.lineTo(X(r.x2),Y(r.y2));ctx.stroke()}ctx.setLineDash([]);}};
"""
def build_ray_diagram(*,rays:list[dict],message:str,seed:int,interface:bool=False,lens:bool=False,lens_sign:int=1,bounds:tuple[float,float,float,float]=(-5,5,-4,4))->str:
    xmin,xmax,ymin,ymax=bounds;config={"durationMs":1800,"autoplay":False,"seed":seed,"tracks":[{"id":"ray-progress","label":"Ray construction","x":[0,1]}],"events":[],"completionMessage":message,"rayConfig":{"rays":rays,"interface":interface,"lens":lens,"lensSign":lens_sign,"xmin":xmin,"xmax":xmax,"ymin":ymin,"ymax":ymax},"view":{"minimum":0,"maximum":1}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=820,logical_height=430,accessible_label="Geometric ray diagram. "+message,idle_hint="Press Play to construct the rays")
